"""Exercism task Exercism_dot-dsl"""
from pathlib import Path

TASK = """Implement the solution defined in dot_dsl.py. Make the tests pass.

Instructions:
# Instructions

A [Domain Specific Language (DSL)][dsl] is a small language optimized for a specific domain.
Since a DSL is targeted, it can greatly impact productivity/understanding by allowing the writer to declare _what_ they want rather than _how_.

One problem area where they are applied are complex customizations/configurations.

For example the [DOT language][dot-language] allows you to write a textual description of a graph which is then transformed into a picture by one of the [Graphviz][graphviz] tools (such as `dot`).
A simple graph looks like this:

    graph {
        graph [bgcolor="yellow"]
        a [color="red"]
        b [color="blue"]
        a -- b [color="green"]
    }

Putting this in a file `example.dot` and running `dot example.dot -T png -o example.png` creates an image `example.png` with red and blue circle connected by a green line on a yellow background.

Write a Domain Specific Language similar to the Graphviz dot language.

Our DSL is similar to the Graphviz dot language in that our DSL will be used to create graph data structures.
However, unlike the DOT Language, our DSL will be an internal DSL for use only in our language.

More information about the difference between internal and external DSLs can be found [here][fowler-dsl].

[dsl]: https://en.wikipedia.org/wiki/Domain-specific_language
[dot-language]: https://en.wikipedia.org/wiki/DOT_(graph_description_language)
[graphviz]: https://graphviz.org/
[fowler-dsl]: https://martinfowler.com/bliki/DomainSpecificLanguage.html

"""

FILES = {
    "dot_dsl.py": 'NODE, EDGE, ATTR = range(3)\n\n\nclass Node:\n    def __init__(self, name, attrs):\n        self.name = name\n        self.attrs = attrs\n\n    def __eq__(self, other):\n        return self.name == other.name and self.attrs == other.attrs\n\n\nclass Edge:\n    def __init__(self, src, dst, attrs):\n        self.src = src\n        self.dst = dst\n        self.attrs = attrs\n\n    def __eq__(self, other):\n        return (self.src == other.src and\n                self.dst == other.dst and\n                self.attrs == other.attrs)\n\n\nclass Graph:\n    def __init__(self, data=None):\n        pass\n',
    "dot_dsl_test.py": 'import unittest\n\nfrom dot_dsl import Graph, Node, Edge, NODE, EDGE, ATTR\n\n\nclass DotDslTest(unittest.TestCase):\n    def test_empty_graph(self):\n        g = Graph()\n\n        self.assertEqual(g.nodes, [])\n        self.assertEqual(g.edges, [])\n        self.assertEqual(g.attrs, {})\n\n    def test_graph_with_one_node(self):\n        g = Graph([\n            (NODE, "a", {})\n        ])\n\n        self.assertEqual(g.nodes, [Node("a", {})])\n        self.assertEqual(g.edges, [])\n        self.assertEqual(g.attrs, {})\n\n    def test_graph_with_one_node_with_keywords(self):\n        g = Graph([\n            (NODE, "a", {"color": "green"})\n        ])\n\n        self.assertEqual(g.nodes, [Node("a", {"color": "green"})])\n        self.assertEqual(g.edges, [])\n        self.assertEqual(g.attrs, {})\n\n    def test_graph_with_one_edge(self):\n        g = Graph([\n            (EDGE, "a", "b", {})\n        ])\n\n        self.assertEqual(g.nodes, [])\n        self.assertEqual(g.edges, [Edge("a", "b", {})])\n        self.assertEqual(g.attrs, {})\n\n    def test_graph_with_one_attribute(self):\n        g = Graph([\n            (ATTR, "foo", "1")\n        ])\n\n        self.assertEqual(g.nodes, [])\n        self.assertEqual(g.edges, [])\n        self.assertEqual(g.attrs, {"foo": "1"})\n\n    def test_graph_with_attributes(self):\n        g = Graph([\n            (ATTR, "foo", "1"),\n            (ATTR, "title", "Testing Attrs"),\n            (NODE, "a", {"color": "green"}),\n            (NODE, "c", {}),\n            (NODE, "b", {"label": "Beta!"}),\n            (EDGE, "b", "c", {}),\n            (EDGE, "a", "b", {"color": "blue"}),\n            (ATTR, "bar", "true")\n        ])\n\n        self.assertEqual(g.nodes, [Node("a", {"color": "green"}),\n                                   Node("c", {}),\n                                   Node("b", {"label": "Beta!"})])\n        self.assertEqual(g.edges, [Edge("b", "c", {}),\n                                   Edge("a", "b", {"color": "blue"})])\n        self.assertEqual(g.attrs, {\n            "foo": "1",\n            "title": "Testing Attrs",\n            "bar": "true"\n        })\n\n    def test_malformed_graph(self):\n        with self.assertRaises(TypeError) as err:\n            Graph(1)\n        self.assertEqual(type(err.exception), TypeError)\n        self.assertEqual(err.exception.args[0], "Graph data malformed")\n\n        with self.assertRaises(TypeError) as err:\n            Graph("problematic")\n        self.assertEqual(type(err.exception), TypeError)\n        self.assertEqual(err.exception.args[0], "Graph data malformed")\n\n    def test_malformed_graph_item(self):\n        with self.assertRaises(TypeError) as err:\n            Graph([()])\n        self.assertEqual(type(err.exception), TypeError)\n        self.assertEqual(err.exception.args[0], "Graph item incomplete")\n\n\n        with self.assertRaises(TypeError) as err:\n                Graph([(ATTR, )])\n        self.assertEqual(type(err.exception), TypeError)\n        self.assertEqual(err.exception.args[0], "Graph item incomplete")\n\n\n    def test_malformed_attr(self):\n        with self.assertRaises(ValueError) as err:\n            Graph([(ATTR, 1, 2, 3)])\n        self.assertEqual(type(err.exception), ValueError)\n        self.assertEqual(err.exception.args[0], "Attribute is malformed")\n\n\n    def test_malformed_node(self):\n        with self.assertRaises(ValueError) as err:\n            Graph([(NODE, 1, 2, 3)])\n        self.assertEqual(type(err.exception), ValueError)\n        self.assertEqual(err.exception.args[0], "Node is malformed")\n\n\n    def test_malformed_EDGE(self):\n        with self.assertRaises(ValueError) as err:\n            Graph([(EDGE, 1, 2)])\n        self.assertEqual(type(err.exception), ValueError)\n        self.assertEqual(err.exception.args[0], "Edge is malformed")\n\n    def test_unknown_item(self):\n        with self.assertRaises(ValueError) as err:\n            Graph([(99, 1, 2)])\n        self.assertEqual(type(err.exception), ValueError)\n        self.assertEqual(err.exception.args[0], "Unknown item")\n'
}

def check(workspace: Path) -> bool:
    import subprocess
    test_code = 'import unittest\n\nfrom dot_dsl import Graph, Node, Edge, NODE, EDGE, ATTR\n\n\nclass DotDslTest(unittest.TestCase):\n    def test_empty_graph(self):\n        g = Graph()\n\n        self.assertEqual(g.nodes, [])\n        self.assertEqual(g.edges, [])\n        self.assertEqual(g.attrs, {})\n\n    def test_graph_with_one_node(self):\n        g = Graph([\n            (NODE, "a", {})\n        ])\n\n        self.assertEqual(g.nodes, [Node("a", {})])\n        self.assertEqual(g.edges, [])\n        self.assertEqual(g.attrs, {})\n\n    def test_graph_with_one_node_with_keywords(self):\n        g = Graph([\n            (NODE, "a", {"color": "green"})\n        ])\n\n        self.assertEqual(g.nodes, [Node("a", {"color": "green"})])\n        self.assertEqual(g.edges, [])\n        self.assertEqual(g.attrs, {})\n\n    def test_graph_with_one_edge(self):\n        g = Graph([\n            (EDGE, "a", "b", {})\n        ])\n\n        self.assertEqual(g.nodes, [])\n        self.assertEqual(g.edges, [Edge("a", "b", {})])\n        self.assertEqual(g.attrs, {})\n\n    def test_graph_with_one_attribute(self):\n        g = Graph([\n            (ATTR, "foo", "1")\n        ])\n\n        self.assertEqual(g.nodes, [])\n        self.assertEqual(g.edges, [])\n        self.assertEqual(g.attrs, {"foo": "1"})\n\n    def test_graph_with_attributes(self):\n        g = Graph([\n            (ATTR, "foo", "1"),\n            (ATTR, "title", "Testing Attrs"),\n            (NODE, "a", {"color": "green"}),\n            (NODE, "c", {}),\n            (NODE, "b", {"label": "Beta!"}),\n            (EDGE, "b", "c", {}),\n            (EDGE, "a", "b", {"color": "blue"}),\n            (ATTR, "bar", "true")\n        ])\n\n        self.assertEqual(g.nodes, [Node("a", {"color": "green"}),\n                                   Node("c", {}),\n                                   Node("b", {"label": "Beta!"})])\n        self.assertEqual(g.edges, [Edge("b", "c", {}),\n                                   Edge("a", "b", {"color": "blue"})])\n        self.assertEqual(g.attrs, {\n            "foo": "1",\n            "title": "Testing Attrs",\n            "bar": "true"\n        })\n\n    def test_malformed_graph(self):\n        with self.assertRaises(TypeError) as err:\n            Graph(1)\n        self.assertEqual(type(err.exception), TypeError)\n        self.assertEqual(err.exception.args[0], "Graph data malformed")\n\n        with self.assertRaises(TypeError) as err:\n            Graph("problematic")\n        self.assertEqual(type(err.exception), TypeError)\n        self.assertEqual(err.exception.args[0], "Graph data malformed")\n\n    def test_malformed_graph_item(self):\n        with self.assertRaises(TypeError) as err:\n            Graph([()])\n        self.assertEqual(type(err.exception), TypeError)\n        self.assertEqual(err.exception.args[0], "Graph item incomplete")\n\n\n        with self.assertRaises(TypeError) as err:\n                Graph([(ATTR, )])\n        self.assertEqual(type(err.exception), TypeError)\n        self.assertEqual(err.exception.args[0], "Graph item incomplete")\n\n\n    def test_malformed_attr(self):\n        with self.assertRaises(ValueError) as err:\n            Graph([(ATTR, 1, 2, 3)])\n        self.assertEqual(type(err.exception), ValueError)\n        self.assertEqual(err.exception.args[0], "Attribute is malformed")\n\n\n    def test_malformed_node(self):\n        with self.assertRaises(ValueError) as err:\n            Graph([(NODE, 1, 2, 3)])\n        self.assertEqual(type(err.exception), ValueError)\n        self.assertEqual(err.exception.args[0], "Node is malformed")\n\n\n    def test_malformed_EDGE(self):\n        with self.assertRaises(ValueError) as err:\n            Graph([(EDGE, 1, 2)])\n        self.assertEqual(type(err.exception), ValueError)\n        self.assertEqual(err.exception.args[0], "Edge is malformed")\n\n    def test_unknown_item(self):\n        with self.assertRaises(ValueError) as err:\n            Graph([(99, 1, 2)])\n        self.assertEqual(type(err.exception), ValueError)\n        self.assertEqual(err.exception.args[0], "Unknown item")\n'
    (workspace / "dot_dsl_test.py").write_text(test_code, encoding="utf-8")
    try:
        res = subprocess.run(["python", "-m", "pytest", "-q", str(workspace / "dot_dsl_test.py")], timeout=15)
        return res.returncode == 0
    except subprocess.TimeoutExpired:
        return False
